// 低功耗策略模式：可组合的电源管理接口

typedef struct {
    const char *name;
    uint8_t max_depth;     // 0=SLEEP, 1=STOP2, 2=STANDBY
    void (*pre_enter)(void);
    void (*post_wakeup)(void);
} power_strategy_t;

// 策略注册表
#define MAX_STRATEGIES 8
static power_strategy_t strategies[MAX_STRATEGIES];
static uint8_t strategy_count = 0;

// 注册策略（调用前确保 HAL 已初始化）
int power_register_strategy(power_strategy_t *s) {
    if (strategy_count >= MAX_STRATEGIES) return -1;
    strategies[strategy_count++] = *s;
    return 0;
}

// 核心入口：选择最深安全模式
void power_manager_enter_sleep(void) {
    // 遍历策略，找到 max_depth 最大的那个
    uint8_t best_depth = 0;
    for (uint8_t i = 0; i < strategy_count; i++) {
        if (strategies[i].max_depth > best_depth) {
            best_depth = strategies[i].max_depth;
        }
    }
    // 执行 pre_enter 回调
    for (uint8_t i = 0; i < strategy_count; i++) {
        if (strategies[i].pre_enter != NULL) {
            strategies[i].pre_enter();
        }
    }
    // 根据 best_depth 进入对应模式
    if (best_depth >= 2) {
        HAL_PWR_EnterSTANDBYMode();
    } else if (best_depth >= 1) {
        HAL_PWR_EnterSTOP2Mode(PWR_LOWPOWERREGULATOR_ON);
    } else {
        HAL_PWR_EnterSLEEPMode(PWR_MAINREGULATOR_ON, PWR_SLEEPENTRY_WFI);
    }
    // 唤醒后执行 post_wakeup
    for (uint8_t i = 0; i < strategy_count; i++) {
        if (strategies[i].post_wakeup != NULL) {
            strategies[i].post_wakeup();
        }
    }
}

// 示例：注册一个 STOP2 策略
static void sensor_pre_enter(void) {
    // 关闭传感器时钟，切换到待机
    __HAL_RCC_I2C3_CLK_DISABLE();
}
static void sensor_post_wakeup(void) {
    // 恢复 I2C，重新初始化传感器
    __HAL_RCC_I2C3_CLK_ENABLE();
    HAL_I2C_Init(&hi2c3);
}

power_strategy_t sensor_strategy = {
    .name = "sensor_stop2",
    .max_depth = 1,
    .pre_enter = sensor_pre_enter,
    .post_wakeup = sensor_post_wakeup
};

/* stop2_power.c - STOP2 模式最小化进入/退出流程 */
#include "stm32l4xx_hal.h"

/* 进睡眠前：关闭不必要的外设时钟 */
static void pre_stop2_enter(void) {
    /* 第 1 步：关闭所有未使用的外设时钟 */
    __HAL_RCC_SPI2_CLK_DISABLE();
    __HAL_RCC_I2C3_CLK_DISABLE();
    __HAL_RCC_DAC1_CLK_DISABLE();
    __HAL_RCC_ADC1_CLK_DISABLE();

    /* 第 2 步：关闭 SRAM2/备份域电源 */
    HAL_PWREx_DisableSRAM2();
    HAL_PWREx_DisableBackupRegulator();

    /* 第 3 步：将未用 GPIO 设为模拟输入（防漏电）*/
    GPIO_TypeDef *unused_ports[] = {GPIOB, GPIOC, GPIOD};
    for (int i = 0; i < 3; i++) {
        unused_ports[i]->MODER = 0x00000000;
    }

    /* 第 4 步：清除唤醒标志（必须在进睡眠前调用）*/
    __HAL_PWR_CLEAR_WUF_FLAG();
}

/* 唤醒后：恢复时钟和外设 */
static void post_stop2_wakeup(void) {
    /* 第 1 步：唤醒后 HSI16 已自动恢复 */
    /* 如果需要高频运行，重新配置 PLL */
    SystemClock_Config();

    /* 第 2 步：恢复外设时钟 */
    __HAL_RCC_SPI2_CLK_ENABLE();
    __HAL_RCC_I2C3_CLK_ENABLE();
    __HAL_RCC_ADC1_CLK_ENABLE();

    /* 第 3 步：恢复 SRAM 电源 */
    HAL_PWREx_EnableSRAM2();

    /* 第 4 步：清除唤醒标志（唤醒后也要清一次）*/
    __HAL_PWR_CLEAR_WUF_FLAG();
}

/* 主循环中的调用 */
void main_loop(void) {
    while (1) {
        /* 处理工作 */
        process_tasks();

        /* 准备进入 STOP2 */
        pre_stop2_enter();

        /* 进入 STOP2 - 此时 CPU 停止，仅 RTC/EXTI 运行 */
        HAL_PWR_EnterSTOP2Mode(PWR_LOWPOWERREGULATOR_ON);

        /* 唤醒后自动执行 */
        post_stop2_wakeup();
    }
}

/* 中断服务函数：唤醒源处理 */
void RTC_Alarm_IRQHandler(void) {
    /* RTC 闹钟唤醒 STOP2 的标准处理 */
    __HAL_RTC_ALARM_CLEAR_FLAG(&hrtc, RTC_FLAG_ALRAF);
    /* 设置标志让主循环知道被闹钟唤醒 */
    set_wakeup_source(WAKEUP_RTC_ALARM);
}

/* 陷阱 2 的修复：批量关闭未用 GPIO 的上拉/下拉 */
void disable_unused_gpio_leakage(void) {
    /* 保存 WKUP 引脚配置 */
    uint32_t wkup_pin = WKUP_PIN_NUMBER;  /* 例如 PA0 = 0 */
    GPIO_TypeDef *wkup_port = WKUP_PORT;   /* 例如 GPIOA */

    /* 遍历所有 GPIO 端口 */
    GPIO_TypeDef *ports[] = {GPIOA, GPIOB, GPIOC, GPIOD,
                             GPIOE, GPIOF, GPIOG};
    int num_ports = 7;

    for (int i = 0; i < num_ports; i++) {
        /* 跳过 WKUP 引脚所在端口 */
        if (ports[i] == wkup_port) continue;

        /* 设为模拟输入（MODER=00），清除上拉/下拉 */
        ports[i]->MODER = 0x00000000;
        ports[i]->PUPDR = 0x00000000;
    }

    /* WKUP 引脚保持上拉配置 */
    wkup_port->PUPDR |= (0x01 << (wkup_pin * 2));
}

/* 陷阱 3 的修复：确认 ADC 电源完全关闭 */
void confirm_adc_power_off(ADC_HandleTypeDef *hadc) {
    /* 禁用时钟 */
    __HAL_RCC_ADC_CLK_DISABLE();

    /* 等待 ADEN 位清零（最多 100 次轮询）*/
    for (int i = 0; i < 100; i++) {
        if ((hadc->Instance->CR & ADC_CR_ADEN) == 0) {
            return; /* 确认关闭 */
        }
        HAL_Delay(1); /* 1ms 间隔 */
    }
    /* 超时仍未关闭，手动清零 */
    hadc->Instance->CR &= ~ADC_CR_ADEN;
}

/* ===== 重构前：if-else 硬编码（坏味道：重复、紧耦合）=====
 * 问题：
 * 1. 新增一种电源模式需要修改 power_enter_deep_sleep()
 * 2. pre/post 逻辑分散在不同函数中
 * 3. 无法组合多个电源策略
 */
void power_enter_deep_sleep(int mode) {
    if (mode == 0) {
        /* SLEEP 模式 */
        __HAL_RCC_SPI2_CLK_DISABLE();
        HAL_PWR_EnterSLEEPMode(...);
        __HAL_RCC_SPI2_CLK_ENABLE();
    } else if (mode == 1) {
        /* STOP2 模式 */
        __HAL_RCC_SPI2_CLK_DISABLE();
        __HAL_RCC_I2C3_CLK_DISABLE();
        HAL_PWREx_DisableSRAM2();
        HAL_PWR_EnterSTOP2Mode(...);
        SystemClock_Config();
        __HAL_RCC_SPI2_CLK_ENABLE();
        __HAL_RCC_I2C3_CLK_ENABLE();
        HAL_PWREx_EnableSRAM2();
    } else if (mode == 2) {
        /* STANDBY 模式 */
        __HAL_RCC_SPI2_CLK_DISABLE();
        __HAL_RCC_I2C3_CLK_DISABLE();
        __HAL_RCC_USB_CLK_DISABLE();
        HAL_PWR_EnterSTANDBYMode();
        /* STANDBY 唤醒后相当于复位，无需恢复 */
    }
}

/* ===== 重构后：策略模式（改进：开闭原则、可组合）=====
 * 改进：
 * 1. 新增策略只需注册，不修改核心代码
 * 2. 每个策略的 pre/post 逻辑内聚
 * 3. 管理器自动选择最深安全模式
 */
typedef struct {
    const char *name;
    uint8_t max_depth;  // 0=SLEEP, 1=STOP2, 2=STANDBY
    void (*pre_enter)(void);
    void (*post_wakeup)(void);
} power_strategy_t;

#define MAX_STRATEGIES 8
static power_strategy_t g_strategies[MAX_STRATEGIES];
static uint8_t g_count = 0;

int register_power_strategy(power_strategy_t *s) {
    if (g_count >= MAX_STRATEGIES) return -1;
    g_strategies[g_count++] = *s;
    return 0;
}

void enter_deep_sleep(void) {
    /* 找最深模式 */
    uint8_t depth = 0;
    for (uint8_t i = 0; i < g_count; i++) {
        if (g_strategies[i].max_depth > depth)
            depth = g_strategies[i].max_depth;
    }
    /* 执行所有 pre_enter */
    for (uint8_t i = 0; i < g_count; i++)
        if (g_strategies[i].pre_enter)
            g_strategies[i].pre_enter();
    /* 进入对应模式 */
    if (depth >= 2)
        HAL_PWR_EnterSTANDBYMode();
    else if (depth >= 1)
        HAL_PWR_EnterSTOP2Mode(PWR_LOWPOWERREGULATOR_ON);
    else
        HAL_PWR_EnterSLEEPMode(PWR_MAINREGULATOR_ON,
                               PWR_SLEEPENTRY_WFI);
    /* 执行所有 post_wakeup */
    for (uint8_t i = 0; i < g_count; i++)
        if (g_strategies[i].post_wakeup)
            g_strategies[i].post_wakeup();
}

/* 使用示例：注册一个 STOP2 策略 */
static void spi_pre_enter(void) {
    __HAL_RCC_SPI2_CLK_DISABLE();
}
static void spi_post_wakeup(void) {
    __HAL_RCC_SPI2_CLK_ENABLE();
}
power_strategy_t spi_strategy = {
    .name = "spi_stop2",
    .max_depth = 1,
    .pre_enter = spi_pre_enter,
    .post_wakeup = spi_post_wakeup
};

/* 注册后，enter_deep_sleep() 自动管理 SPI 时钟 */
register_power_strategy(&spi_strategy);
